#include<bits/stdc++.h>
using namespace std;
int a[105][25];
int q[105];
int w[105];
int main(){
	int n,m;
	cin>>n>>m;
	int sum=0;
	for(int i=1;i<=n;i++){
		w[i]=15;
	}
	for(int i=1;i<=n;i++){ 
		for(int j=1;j<=m;j++){
			cin>>a[i][j];
			w[i]=min(a[i][j],w[i]);
			q[i]=max(a[i][j],q[i]);//记录最高分和最低分。
		}
	}

	for(int i=1;i<=n;i++){
		int s=0;
		for(int j=1;j<=m;j++){
			s+=a[i][j];
		}
		s-=w[i];
		s-=q[i];
		sum=max(sum,s);
	} 
	printf("%.2lf",sum/1.0/(m-2));
}
